namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string CourseCode { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public string DepartmentName { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Abbreviation { get; set; } = string.Empty;
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    public string StudentName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CourseCatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CourseCatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Abbreviation = "CS" },
            new() { Id = 2, Name = "Mathematics", Abbreviation = "MATH" },
            new() { Id = 3, Name = "Physics", Abbreviation = "PHYS" },
            new() { Id = 4, Name = "English", Abbreviation = "ENG" },
            new() { Id = 5, Name = "History", Abbreviation = "HIST" }
        };

        _courses = new List<Course>
        {
            new()
            {
                Id = 1, CourseCode = "CS 101", Title = "Introduction to Programming",
                Description = "An introductory course covering fundamental programming concepts including variables, control structures, functions, and basic data structures. Students will learn to write programs in C# and develop problem-solving skills applicable across languages.",
                Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen",
                InstructorBio = "Dr. Chen holds a PhD in Computer Science from MIT and has 15 years of teaching experience. Her research focuses on programming language design and CS education.",
                DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true
            },
            new()
            {
                Id = 2, CourseCode = "CS 201", Title = "Data Structures and Algorithms",
                Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs, hash tables) and algorithms (sorting, searching, graph traversal). Emphasis on algorithm analysis and selecting appropriate data structures for real-world problems.",
                Credits = 4, Schedule = "Tue/Thu 10:30 AM–12:00 PM", InstructorName = "Dr. James Wright",
                InstructorBio = "Dr. Wright is an ACM Distinguished Educator with expertise in algorithm design. He previously worked at Google Research before joining academia.",
                DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true
            },
            new()
            {
                Id = 3, CourseCode = "CS 310", Title = "Database Systems",
                Description = "Principles of database design, relational algebra, SQL, normalization, transaction processing, and query optimization. Includes a semester-long project building a complete database application.",
                Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", InstructorName = "Dr. Maria Rodriguez",
                InstructorBio = "Dr. Rodriguez specializes in distributed database systems and has published extensively on query optimization techniques.",
                DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false
            },
            new()
            {
                Id = 4, CourseCode = "MATH 151", Title = "Calculus I",
                Description = "Limits, continuity, derivatives of single-variable functions, and applications of differentiation. Covers techniques of integration and the Fundamental Theorem of Calculus.",
                Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Robert Kim",
                InstructorBio = "Dr. Kim is an award-winning mathematics educator known for making calculus accessible. He has authored two widely-used textbooks.",
                DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = true
            },
            new()
            {
                Id = 5, CourseCode = "MATH 250", Title = "Linear Algebra",
                Description = "Vector spaces, linear transformations, matrices, determinants, eigenvalues and eigenvectors. Applications to systems of equations, geometry, and data science.",
                Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", InstructorName = "Dr. Emily Park",
                InstructorBio = "Dr. Park researches applications of linear algebra in machine learning. She brings industry experience from her time at a data science startup.",
                DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false
            },
            new()
            {
                Id = 6, CourseCode = "PHYS 101", Title = "General Physics I",
                Description = "Mechanics, thermodynamics, and waves. Topics include kinematics, Newton's laws, energy, momentum, rotational motion, and oscillations. Laboratory component included.",
                Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM + Lab Thu 2:00–4:00 PM", InstructorName = "Dr. Alan Foster",
                InstructorBio = "Dr. Foster is an experimental physicist whose research in materials science informs his teaching. He emphasizes hands-on learning in all his courses.",
                DepartmentId = 3, DepartmentName = "Physics", IsFeatured = false
            },
            new()
            {
                Id = 7, CourseCode = "PHYS 220", Title = "Electromagnetism",
                Description = "Electric fields, Gauss's law, electric potential, capacitance, current, magnetic fields, Faraday's law, and Maxwell's equations. Builds on General Physics I.",
                Credits = 4, Schedule = "Tue/Thu 9:00–10:15 AM + Lab Fri 1:00–3:00 PM", InstructorName = "Dr. Lisa Nguyen",
                InstructorBio = "Dr. Nguyen is a theoretical physicist specializing in electromagnetic theory. She received the university's Excellence in Teaching award in 2024.",
                DepartmentId = 3, DepartmentName = "Physics", IsFeatured = true
            },
            new()
            {
                Id = 8, CourseCode = "ENG 110", Title = "College Writing",
                Description = "Develops essential academic writing skills including argumentation, research methods, source evaluation, and revision strategies. Students produce multiple essays across genres.",
                Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Prof. David Morrison",
                InstructorBio = "Prof. Morrison is a published author and writing instructor with 20 years of experience in composition pedagogy.",
                DepartmentId = 4, DepartmentName = "English", IsFeatured = false
            },
            new()
            {
                Id = 9, CourseCode = "ENG 245", Title = "American Literature",
                Description = "Survey of American literature from the colonial period to the present. Examines major works in their historical and cultural contexts, covering poetry, fiction, and nonfiction.",
                Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:15 PM", InstructorName = "Dr. Angela Brooks",
                InstructorBio = "Dr. Brooks specializes in 20th-century American fiction. Her book on the Harlem Renaissance received critical acclaim.",
                DepartmentId = 4, DepartmentName = "English", IsFeatured = false
            },
            new()
            {
                Id = 10, CourseCode = "HIST 101", Title = "World Civilizations",
                Description = "A broad survey of world history from ancient civilizations to the modern era. Explores political, social, economic, and cultural developments across regions.",
                Credits = 3, Schedule = "Mon/Wed 3:30–4:45 PM", InstructorName = "Dr. Thomas Grant",
                InstructorBio = "Dr. Grant is a historian of global trade networks. He has conducted fieldwork across four continents and brings diverse perspectives to the classroom.",
                DepartmentId = 5, DepartmentName = "History", IsFeatured = false
            }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? searchTerm = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);
}

