@page "/"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CourseCatalogService CatalogService

<PageTitle>Home - University Course Catalog</PageTitle>

<div class="text-center mb-5">
    <h2 class="display-5">Welcome to the University Course Catalog</h2>
    <p class="lead text-muted">Browse courses, explore departments, and enroll for the upcoming semester.</p>
    <a href="/courses" class="btn btn-primary btn-lg mt-2">Browse All Courses</a>
</div>

<section class="mb-5">
    <h3>Featured Courses</h3>
    <div class="row g-3 mt-2">
        @foreach (var course in featuredCourses)
        {
            <div class="col-md-6 col-lg-3">
                <div class="card h-100">
                    <div class="card-body">
                        <h6 class="card-subtitle text-muted mb-1">@course.CourseCode</h6>
                        <h5 class="card-title">@course.Title</h5>
                        <p class="card-text small">@course.Credits credits &bull; @course.DepartmentName</p>
                    </div>
                    <div class="card-footer bg-transparent border-0">
                        <a href="/courses/@course.Id" class="btn btn-outline-primary btn-sm">View Details</a>
                    </div>
                </div>
            </div>
        }
    </div>
</section>

<section>
    <h3>Departments</h3>
    <div class="row g-3 mt-2">
        @foreach (var dept in departments)
        {
            <div class="col-md-4 col-lg-2">
                <a href="/courses?departmentId=@dept.Id" class="text-decoration-none">
                    <div class="card text-center p-3 h-100">
