@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CourseCatalogService CatalogService

<PageTitle>Courses - University Course Catalog</PageTitle>

<h2>Course Catalog</h2>

<form method="get" class="row g-3 mb-4 mt-2">
    <div class="col-md-6">
        <input type="text" name="search" value="@Search" class="form-control" placeholder="Search by title, code, or instructor..." />
    </div>
    <div class="col-md-4">
        <select name="departmentId" class="form-select">
            <option value="">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button type="submit" class="btn btn-primary w-100">Filter</button>
    </div>
</form>

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses found matching your criteria.</div>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Department</th>
                    <th>Credits</th>
                    <th>Instructor</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in courses)
                {
                    <tr>
                        <td>@course.CourseCode</td>
                        <td>@course.Title</td>
                        <td>@course.DepartmentName</td>
                        <td>@course.Credits</td>
                        <td>@course.InstructorName</td>
                        <td><a href="/courses/@course.Id" class="btn btn-sm btn-outline-secondary">Details</a></td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
    <p class="text-muted"><small>Showing @courses.Count course(s)</small></p>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<Course> courses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        courses = CatalogService.GetCourses(Search, DepartmentId);
    }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CourseCatalogService CatalogService

<PageTitle>@(course?.Title ?? "Course Not Found") - University Course Catalog</PageTitle>

@if (course is null)
{
    <div class="alert alert-warning">Course not found.</div>
    <a href="/courses" class="btn btn-secondary">Back to Courses</a>
}
else
{
    <nav aria-label="breadcrumb" class="mb-3">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/courses">Courses</a></li>
            <li class="breadcrumb-item"><a href="/courses?departmentId=@course.DepartmentId">@course.DepartmentName</a></li>
            <li class="breadcrumb-item active">@course.CourseCode</li>
        </ol>
    </nav>

    <div class="row">
        <div class="col-lg-8">
            <h2>@course.Title</h2>
            <span class="badge bg-secondary mb-3">@course.CourseCode</span>

            <h5 class="mt-4">Description</h5>
            <p>@course.Description</p>

            <h5>Schedule</h5>
            <p>@course.Schedule</p>

            <h5>Credits</h5>
            <p>@course.Credits</p>
        </div>
        <div class="col-lg-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Instructor</h5>
                    <h6>@course.InstructorName</h6>
                    <p class="card-text small">@course.InstructorBio</p>
                </div>
            </div>
            <div class="mt-3">
                <a href="/enroll?courseId=@course.Id" class="btn btn-success w-100">Enroll in This Course</a>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Course? course;

    protected override void OnInitialized()
    {
        course = CatalogService.GetCourse(Id);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CourseCatalogService CatalogService

<PageTitle>Enroll - University Course Catalog</PageTitle>

<h2>Enrollment Request</h2>
<p class="text-muted">Submit your enrollment request below. You will receive confirmation via your university email.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h5>Enrollment Request Submitted!</h5>
        <p class="mb-0">Thank you, <strong>@Model.StudentName</strong>. Your request to enroll in <strong>@selectedCourseTitle</strong> has been received and is being processed.</p>
    </div>
    <a href="/courses" class="btn btn-primary">Browse More Courses</a>
}
else
{
    <div class="row">
        <div class="col-lg-6">
            <EditForm Model="Model" FormName="enrollment" OnValidSubmit="HandleSubmit" method="post">
                <AntiforgeryToken />
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />

                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <InputText id="studentName" @bind-Value="Model.StudentName" class="form-control" />
                    <ValidationMessage For="() => Model.StudentName" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <InputText id="studentId" @bind-Value="Model.StudentId" class="form-control" />
                    <ValidationMessage For="() => Model.StudentId" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <InputSelect id="courseId" @bind-Value="Model.CourseId" class="form-select">
                        <option value="0">-- Select a course --</option>
                        @foreach (var course in courses)
                        {
                            <option value="@course.Id">@course.CourseCode - @course.Title</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => Model.CourseId" class="text-danger" />
                </div>

                <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
            </EditForm>
        </div>
    </div>
}

@code {
    [SupplyParameterFromForm] private EnrollmentRequest Model { get; set; } = new();
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private List<Course> courses = new();
    private bool submitted;
    private string selectedCourseTitle = string.Empty;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetCourses();
        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        var course = CatalogService.GetCourse(Model.CourseId);
        selectedCourseTitle = course is not null ? $"{course.CourseCode} - {course.Title}" : "Unknown";
        submitted = true;
    }
}

